class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def delete(self, word: str) -> None:
        self._delete_recursive(self.root, word, 0)

    def _delete_recursive(self, current_node: TrieNode, word: str, index: int) -> bool:
        if index == len(word):
            if not current_node.is_end_of_word:
                return False

            current_node.is_end_of_word = False

            return len(current_node.children) == 0

        char = word[index]
        if char not in current_node.children:
            return False

        should_delete_child = self._delete_recursive(current_node.children[char], word, index + 1)

        if should_delete_child:
            del current_node.children[char]

            return len(current_node.children) == 0 and not current_node.is_end_of_word

        return False
